var parent = current.getValue("parent") || '';
// DFCT0011822
// STRY0146507 - Certification Failed Test Resutls - NOT FIXING - Task permissions drives email on the task permissions
var grTask = new GlideRecord("x_153465_discovert_route_task_instance");
var allow = false;
// DFCT0011857  new record is checked a different way, so allow
if(current.isNewRecord()){
	allow = true;
} else if(parent !=''){
	if(grTask.get(parent)){
		allow = grTask.canRead();
	}
}
answer = allow;
